return items.map(item => {
  const result = item.json.result || [];

  const get = (code) => {
    const found = result.find(d => d.code === code);
    return found ? found.value : null;
  };

  // --- valeurs brutes ---
  const rawSwitch        = get('switch');
  const rawCountdown     = get('countdown_1');
  const rawAddEle        = get('add_ele');
  const rawCurrent       = get('cur_current');
  const rawPower         = get('cur_power');
  const rawVoltage       = get('cur_voltage');
  const rawTestBit       = get('test_bit');
  const rawVoltageCoe    = get('voltage_coe');
  const rawElectricCoe   = get('electric_coe');
  const rawPowerCoe      = get('power_coe');
  const rawElectricityCoe= get('electricity_coe');
  const rawFault         = get('fault');
  const relayStatus      = get('relay_status');
  const lightMode        = get('light_mode');
  const childLock        = get('child_lock');
  const cycleTime        = get('cycle_time');
  const onlineState      = get('online_state');

  // --- conversions en unités réelles (à ajuster selon ton modèle) ---

  // Tension : plupart des Tuya → 0.1 V
  const voltage_V = (rawVoltage !== null && rawVoltage !== undefined)
    ? rawVoltage / 10
    : null;

  // Courant : la plupart des modules Tuya → mA * 10 → /1000 pour avoir des A
  const current_A = (rawCurrent !== null && rawCurrent !== undefined)
    ? rawCurrent / 1000
    : null;

  // Puissance : souvent 0.1 W
  const power_W = (rawPower !== null && rawPower !== undefined)
    ? rawPower / 10
    : null;

  // Énergie cumulée : souvent 0.01 kWh
  // Si tu vois des valeurs bizarres, tu peux tester /10 ou /1000
  const energy_kWh = (rawAddEle !== null && rawAddEle !== undefined)
    ? rawAddEle / 100
    : null;

  // Compte à rebours en secondes -> minutes (optionnel)
  const countdown_seconds = rawCountdown;
  const countdown_minutes = (typeof rawCountdown === 'number')
    ? rawCountdown / 60
    : null;

  // État de défaut : 0 = OK, autre = problème (à affiner avec la doc Tuya)
  const hasFault = rawFault !== null && rawFault !== 0;

  return {
    json: {
      // On garde le JSON d'origine si besoin
      ...item.json,

      // --- Vue "humaine" ---
      tuya: {
        switch_on: rawSwitch === true,
        online: onlineState === 'online',
        child_lock: childLock === true,
        relay_status: relayStatus,  // "last", "on", "off"...
        light_mode: lightMode,      // "relay", "none", etc.

        // Mesures
        voltage: {
          value: voltage_V,
          unit: 'V',
          raw: rawVoltage,
        },
        current: {
          value: current_A,
          unit: 'A',
          raw: rawCurrent,
        },
        power: {
          value: power_W,
          unit: 'W',
          raw: rawPower,
        },
        energy: {
          value: energy_kWh,
          unit: 'kWh',
          raw: rawAddEle,
          note: 'Facteur 0.01 kWh, à ajuster si besoin',
        },

        // Minuteur
        countdown: {
          seconds: countdown_seconds,
          minutes: countdown_minutes,
        },

        // Diagnostic
        fault: {
          raw: rawFault,
          has_fault: hasFault,
        },
        test_bit: rawTestBit,

        // Coefficients de calibration (pour debug / calibration avancée)
        calibration: {
          voltage_coe: rawVoltageCoe,
          electric_coe: rawElectricCoe,
          power_coe: rawPowerCoe,
          electricity_coe: rawElectricityCoe,
        },

