// Rank KB_ENTRY candidates with a simple lexical score (MVP)

const q = $node["Normalisation de la Demande"].json.query_norm || "";

// KB_POLICY (limit 1) -> string => number
const pol = $node["Lire la politique KB"].json;
const t_exact = parseFloat(pol.t_exact || "0.75");

// tokenisation : mots >= 3 caractères
const qTokens = q
  .split(/\s+/)
  .map(s => s.trim())
  .filter(s => s.length >= 3);

function scoreText(text) {
  if (!text) return 0;
  const t = text.toString().toLowerCase();
  let hits = 0;
  for (const tok of qTokens) {
    if (t.includes(tok)) hits++;
  }
  return qTokens.length ? hits / qTokens.length : 0;
}

let best = null;
