  const row = it.json;

  // ignore les lignes vides
  if (!row || !row.kb_id || !row.title) continue;

  const titleScore = scoreText(row.title);

  // tags: string "a,b,c" ou null
  const tagsText = (row.tags || "").toString().replace(/,/g, " ");
  const tagsScore = scoreText(tagsText);

  const intentScore = scoreText(row.intent || "");

  // pondération simple
  const s = (0.55 * titleScore) + (0.35 * tagsScore) + (0.10 * intentScore);

  if (s > bestScore) {
    bestScore = s;
    best = row;
  }
}

