 * Ce Function node prend en entrée des items dont `item.json` est :
 *  - soit un objet Tuya :
 *      {
 *        "result": [ { "code": "...", "value": ... }, ... ],
 *        "success": true,
 *        "t": 1763811513695,
 *        "tid": "..."
 *      }
 *
 *  - soit un tableau d'objets Tuya (comme dans ton exemple) :
 *      [
 *        { "result": [...], "success": true, "t": ..., "tid": "..." },
 *        { "result": [...], "success": true, "t": ..., "tid": "..." }
 *      ]
 *
 * Il renvoie :
 *  - un item par objet Tuya
 *  - avec un JSON "plat" + une structuration par canal (switch_1, switch_2, etc.)
 */

function parseTuyaEntry(entry) {
  const result = entry.result || [];

  const flat = {};
  const channels = {}; // ex: channels["1"] = { switch: false, countdown: 0, ... }

  for (const item of result) {
    const code = item.code;
    const value = item.value;

    flat[code] = value;

    // Détection des patterns du type "xxx_1", "xxx_2", etc.
    const m = /^([^_]+)_(\d+)$/.exec(code);
    if (m) {
      const base = m[1];   // ex: "switch", "countdown"
      const index = m[2];  // ex: "1", "2"

      if (!channels[index]) {
        channels[index] = {};
      }

      channels[index][base] = value;
    }
  }

  // Meta-infos Tuya
  flat._success = entry.success;
  flat._timestamp = entry.t;
  flat._tid = entry.tid;

  // Vue structurée
  const structured = {
    raw: entry,
    flat,
    channels,
  };

  return structured;
}

