  params.last_id = lastId;
}

// Tri des clés par ordre alphabétique (exigé par Tuya v2)
const keys = Object.keys(params).sort();

// Construction de la query triée
const query = keys
  .map((k) => `${k}=${encodeURIComponent(params[k])}`)
  .join('&');

